3098 /// Perform a purely local form of PRE that looks for diamond
3099 /// control flow patterns and attempts to perform simple PRE at the join point.
3100 bool GVNPass::performPRE(Function &F) {
3101   bool Changed = false;
3102   for (BasicBlock *CurrentBlock : depth_first(&F.getEntryBlock())) {
3103     // Nothing to PRE in the entry block.
3104     if (CurrentBlock == &F.getEntryBlock())
3105       continue;
3106 
3107     // Don't perform PRE on an EH pad.
3108     if (CurrentBlock->isEHPad())
3109       continue;
3110 
3111     for (BasicBlock::iterator BI = CurrentBlock->begin(),
3112                               BE = CurrentBlock->end();
3113          BI != BE;) {
3114       Instruction *CurInst = &*BI++;
3115       Changed |= performScalarPRE(CurInst);
3116     }
3117   }
3118 
3119   if (splitCriticalEdges())
3120     Changed = true;
3121 
3122   return Changed;
3123 }
